  akty_prawne: sections.acts.slice(0, 8).map(({ title, date, meta, reason, signals }) => ({ title, date, meta, reason, signals })),
  interpelacje: sections.interpellations.slice(0, 8).map(({ title, date, meta, reason, signals }) => ({ title, date, meta, reason, signals })),
  zapytania: sections.writtenQuestions.slice(0, 8).map(({ title, date, meta, reason, signals }) => ({ title, date, meta, reason, signals })),
  komisje: sections.committees.slice(0, 8).map(({ title, date, meta, body }) => ({ title, date, meta, agenda: body })),
  glosowania: sections.votings.slice(0, 8).map(({ title, date, meta, reason, signals }) => ({ title, date, meta, reason, signals })),
  bledy_zrodel: errors
};

const systemPrompt = `Jestes analitykiem cyberbezpieczenstwa i legislacji. Pisz po polsku, formalnie, krotko i rzeczowo. Masz przygotowac komentarz do newslettera na podstawie danych juz odfiltrowanych z oficjalnych API. Kazda pozycja ma pole reason, ktore wyjasnia zwiazek z cyberbezpieczenstwem lub cyfryzacja. Nie dodawaj faktow spoza danych. Jesli liczba trafien jest mala, powiedz to wprost. Zwracaj tylko fragment HTML: kilka akapitow i ewentualnie krotkie <strong>, bez <html>, <head>, <body>, bez tabel.`;
const userPrompt = `Na podstawie danych ponizej napisz sekcje "Komentarz analityczny" dla newslettera Cyber-monitor Sejmowy za okres ${dateContext.dateFrom} - ${dateContext.dateTo}.

Wymagania:
- zacznij od <h2>Komentarz analityczny</h2>;
- 2-4 akapity <p>;
- wskaz najwazniejsze obszary ryzyka/uwagi dla administracji publicznej;
- nie uzasadniaj pozycji ogolnikowo; korzystaj z pol reason/signals;
- jezeli totalFound=${totalFound}, uwzglednij skale znalezisk;
- jezeli sa bledy zrodel, zasygnalizuj ograniczenie danych bez technicznego tonu.

Dane JSON:
${JSON.stringify(compact, null, 2)}`;

return [{ json: { ...data, systemPrompt, userPrompt } }];

const source = $('Agreguj i filtruj dane').item.json;
const dateCtx = source.dateContext;
const sections = source.sections;
const stats = source.stats;
const errors = source.errors || [];
const llm = $input.item.json;
const escapeHtml = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const cleanFragment = (value) => {
  const raw = String(value || '').trim();
  if (!raw || llm.error) {
    return '<h2>Komentarz analityczny</h2><p>Nie udalo sie wygenerowac komentarza LLM, ale ponizsze sekcje zawieraja deterministycznie zebrane wyniki z oficjalnych zrodel.</p>';
  }
  return raw
    .replace(/```html/gi, '')
    .replace(/```/g, '')
    .replace(/<\/?(?:html|head|body)[^>]*>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .trim();
};
const itemCard = (item) => {
  const title = escapeHtml(item.title || 'Brak tytulu');
  const reason = item.reason ? `<div class="item-body reason"><strong>Dlaczego w monitoringu:</strong> ${escapeHtml(item.reason)}</div>` : '';
  const body = item.body ? `<div class="item-body"><strong>Opis zrodla:</strong> ${escapeHtml(item.body)}</div>` : '';
  const url = item.url ? `<a href="${escapeHtml(item.url)}">zrodlo</a>` : '';
  const meta = [item.date, item.meta, url].filter(Boolean).join(' | ');
  return `<div class="item-card">
    <div class="item-title">${title}</div>
    ${reason}
    ${body}
    <div class="item-meta">${escapeHtml(item.type || '')}${meta ? ' | ' + meta : ''}</div>
  </div>`;
};
const sectionHtml = (heading, items, emptyText) => {
  const content = items && items.length ? items.map(itemCard).join('\n') : `<p class="empty-state">${escapeHtml(emptyText || 'W tym tygodniu nie odnotowano trafien w tej kategorii.')}</p>`;
  return `<h2>${heading}</h2>\n${content}`;
};
const statChip = (label, value) => `<div class="stat-chip"><span>${escapeHtml(label)}</span><strong>${Number(value || 0)}</strong></div>`;
const warning = errors.length ? `<div class="notice"><strong>Uwaga:</strong> ${errors.length} zrodel zwrocilo blad lub timeout. Newsletter zawiera dane z pozostalych zrodel, a szczegoly sa w execution logu n8n.</div>` : '';
const analysis = cleanFragment(llm.text || llm.output || llm.response || '');
const subject = `Cyber-monitor Sejmowy | Tydzien ${dateCtx.weekNumber}/${dateCtx.year} (${dateCtx.dateFrom} - ${dateCtx.dateTo})`;
const total = Object.values(sections).flat().length;
const htmlContent = `<!DOCTYPE html>
