      <div class="kicker">Cyberbezpieczenstwo | Cyfryzacja | Sejm RP</div>
      <h1>Cyber-monitor Sejmowy</h1>
      <p>Tygodniowy monitoring legislacyjny: ${escapeHtml(dateCtx.dateFrom)} - ${escapeHtml(dateCtx.dateTo)} | tydzien ${escapeHtml(dateCtx.weekNumber)}/${escapeHtml(dateCtx.year)}</p>
    </div>
    <div class="stats">
      ${statChip('Wszystkie trafienia', total)}
      ${statChip('Druki i akty', (sections.prints?.length || 0) + (sections.acts?.length || 0))}
      ${statChip('Interpelacje i zapytania', (sections.interpellations?.length || 0) + (sections.writtenQuestions?.length || 0))}
      ${statChip('Komisje i glosowania', (sections.committees?.length || 0) + (sections.votings?.length || 0))}
    </div>
    <div class="content">
