      ${sectionHtml('Akty prawne: Dz.U. i M.P.', sections.acts, 'Brak nowych aktow prawnych w ELI z jasnym zwiazkiem z cyberbezpieczenstwem lub cyfryzacja.')}
      ${sectionHtml('Interpelacje', sections.interpellations, 'Brak interpelacji z ostatnimi zmianami i jasnym zwiazkiem z cyberbezpieczenstwem lub cyfryzacja.')}
      ${sectionHtml('Zapytania poselskie', sections.writtenQuestions, 'Brak zapytan poselskich z ostatnimi zmianami i jasnym zwiazkiem z cyberbezpieczenstwem lub cyfryzacja.')}
      ${sectionHtml('Komisje i podkomisje', sections.committees, 'Brak posiedzen komisji z agendami pasujacymi do profilu cyber/cyfryzacja.')}
      ${sectionHtml('Glosowania', sections.votings, 'Brak glosowan pasujacych do profilu cyber/cyfryzacja.')}
      ${sectionHtml('Posiedzenia Sejmu', sections.proceedings, 'Brak posiedzen Sejmu w monitorowanym zakresie dat.')}
    </div>
    <div class="footer">
      Zrodla: <a href="https://api.sejm.gov.pl">api.sejm.gov.pl</a>, API ELI Sejmu RP. Surowe odpowiedzi sa filtrowane w n8n przed wysylka, aby ograniczyc pominiecia i obciazenie instancji Proxmox. Newsletter ma charakter informacyjny i nie jest opinia prawna.<br>
      Diagnostyka zrodel: pobrano m.in. druki ${escapeHtml(stats.rawPrints)}, interpelacje ${escapeHtml(stats.rawInterpellations)}, zapytania ${escapeHtml(stats.rawWrittenQuestions)}, akty ELI ${escapeHtml(stats.rawEliActs)}, posiedzenia komisji ${escapeHtml(stats.rawCommittees)}, szczegoly glosowan ${escapeHtml(stats.rawVotingDetails)}.
    </div>
  </div>
</body>
</html>`;
const textContent = htmlContent.replace(/<style[\s\S]*?<\/style>/gi, ' ').replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim();

return [{
  json: {
    fromEmail: dateCtx.fromEmail,
    toEmail: dateCtx.toEmail,
    subject,
    htmlContent,
    textContent,
    totalFound: total,
    stats,
    sourceErrors: errors
  }
}];

const emailData = $input.item.json;
const recipients = [
  { email: 'michalreczek@gmail.com', name: 'Michal Reczek' }
];
return recipients.map((recipient) => ({
  json: {
    ...emailData,
    recipientEmail: recipient.email,
    recipientName: recipient.name
  }
}));

const results = $input.all();
const sent = results.filter((item) => item.json.id).length;
const failed = results.length - sent;
return [{
  json: {
    summary: `Wyslano: ${sent}; bledy: ${failed}`,
    sent,
    failed,
    timestamp: new Date().toISOString(),
    results: results.map((item) => ({
      id: item.json.id || null,
      status: item.json.id ? 'sent' : 'error',
      message: item.json.message || item.json.error || null
    }))
  }
}];
